# Systematizing Your Prompts

Stop rewriting prompts from scratch. Build a library of proven, reusable prompts.

## The Value of Prompt Libraries

```python
prompt_library_benefits = [
    "Consistency - Same task, same quality output",
    "Efficiency - Don't reinvent the wheel",
    "Iterative improvement - Version and refine",
    "Knowledge sharing - Team uses proven prompts",
    "Documentation - Prompts are documented assets"
]
```

## Prompt Library Structure

```python
prompt_library = {
    "summarize": {
        "id": "sum-001",
        "name": "Text Summarizer",
        "description": "Summarize text to specified length",
        "version": "1.2",
        "template": """
Summarize the following text in approximately {word_count} words.

Focus on: {focus_areas}

Text:
{text}

Summary:
""",
        "parameters": {
            "text": {"type": "string", "required": True},
            "word_count": {"type": "int", "default": 100},
            "focus_areas": {"type": "string", "default": "main points"}
        },
        "examples": [
            {
                "input": {"text": "Long article...", "word_count": 50},
                "output": "Summary..."
            }
        ],
        "metadata": {
            "created": "2024-01-15",
            "author": "Team",
            "tags": ["summarization", "general"],
            "best_for": ["articles", "documents", "reports"]
        }
    }
}
```

## Prompt Template Class

```python
from string import Template
from typing import Dict, Any, List

class PromptTemplate:
    def __init__(self, 
                 template: str,
                 required_params: List[str],
                 optional_params: Dict[str, Any] = None,
                 examples: List[Dict] = None):

        self.template = Template(template)
        self.required_params = required_params
        self.optional_params = optional_params or {}
        self.examples = examples or []

    def render(self, **kwargs) -> str:
        """Render prompt with provided parameters."""
        # Check required params
        missing = set(self.required_params) - set(kwargs.keys())
        if missing:
            raise ValueError(f"Missing required parameters: {missing}")

        # Merge with defaults
        params = {**self.optional_params, **kwargs}

        return self.template.safe_substitute(params)

    def validate(self, **kwargs) -> bool:
        """Check if parameters are valid."""
        return all(param in kwargs for param in self.required_params)

    def add_example(self, input_dict: Dict, output: str):
        """Add example to the template."""
        self.examples.append({"input": input_dict, "output": output})

# Usage
summary_template = PromptTemplate(
    template="""
Summarize in ${word_count} words.
Focus on: ${focus}

Text: ${text}

Summary:
""",
    required_params=["text"],
    optional_params={"word_count": "100", "focus": "main points"}
)

prompt = summary_template.render(
    text="Long article content here...",
    word_count="50",
    focus="key findings"
)
print(prompt)
```

