## Library Implementation

```python
import json
from pathlib import Path

class PromptLibrary:
    def __init__(self, library_path: str = "prompts/"):
        self.library_path = Path(library_path)
        self.library_path.mkdir(exist_ok=True)
        self.prompts = {}
        self._load_library()

    def _load_library(self):
        """Load all prompts from library."""
        for file in self.library_path.glob("*.json"):
            with open(file) as f:
                prompt_data = json.load(f)
                self.prompts[prompt_data["id"]] = prompt_data

    def get(self, prompt_id: str) -> PromptTemplate:
        """Get a prompt template by ID."""
        if prompt_id not in self.prompts:
            raise KeyError(f"Prompt {prompt_id} not found")

        data = self.prompts[prompt_id]
        return PromptTemplate(
            template=data["template"],
            required_params=data.get("required_params", []),
            optional_params=data.get("optional_params", {}),
            examples=data.get("examples", [])
        )

    def search(self, query: str) -> List[Dict]:
        """Search prompts by query."""
        results = []
        for prompt_id, data in self.prompts.items():
            if (query.lower() in data.get("name", "").lower() or
                query.lower() in data.get("description", "").lower() or
                query.lower() in str(data.get("tags", []))):
                results.append(data)
        return results

    def add(self, prompt_data: Dict):
        """Add new prompt to library."""
        prompt_id = prompt_data["id"]
        self.prompts[prompt_id] = prompt_data

        # Save to file
        file_path = self.library_path / f"{prompt_id}.json"
        with open(file_path, 'w') as f:
            json.dump(prompt_data, f, indent=2)

    def list_all(self) -> List[str]:
        """List all prompt IDs."""
        return list(self.prompts.keys())

# Usage
library = PromptLibrary()

# Get a prompt
summarizer = library.get("summarize-001")
prompt = summarizer.render(text="Article content...")

# Search for prompts
results = library.search("code")

# Add new prompt
library.add({
    "id": "review-code-001",
    "name": "Code Review",
    "template": "Review this code:\n${code}\n\nProvide: issues, suggestions, improvements.",
    "required_params": ["code"],
    "tags": ["code", "review", "quality"]
})
```

